var Canvas = require('canvas')
  , fs = require('fs');

exports.resize = function(source, destination, dimensions, callback) {

  fs.stat(source, function(err, stats) {

    if (stats && stats.size) {

      console.log(source);

      fs.readFile(source, function(err, data) {

        if (err) throw err;

        var img = new Canvas.Image;

        img.src = data;

        var ratio = dimensions.width?dimensions.width/img.width:dimensions.height/img.height
          , canvas = new Canvas(ratio*img.width, ratio*img.height)
          , ctx = canvas.getContext('2d');

        ctx.imageSmoothingEnabled = true;

        ctx.drawImage(img, 0, 0, ratio*img.width, ratio*img.height);

        var out = fs.createWriteStream(destination)
          , stream = canvas.jpegStream();

        stream.on('data', function(chunk) {
          out.write(chunk);
        });

        stream.on('end', function() {
          // avoid premature end of jpeg file error
          setTimeout(function() {
            callback(true);
          }, 5);
        });

      });

    } else {
      callback(false);
    }

  });

};

exports.thumbnailize = function(source, destination, dimensions, callback) {

  fs.readFile(source, function(err, data) {

    if (err) throw err;

    var img = new Canvas.Image
      , canvas = new Canvas(dimensions.width, dimensions.height)
      , ctx = canvas.getContext('2d');

    ctx.imageSmoothingEnabled = true;

    img.src = data;

    if (img.height/img.width < dimensions.height/dimensions.width) {

      var resize = dimensions.height / img.height
        , crop = (resize*img.width - dimensions.width)/resize;

      ctx.drawImage(img, crop/2, 0, img.width - crop, img.height, 0, 0, dimensions.width, dimensions.height);

    } else {

      var resize = dimensions.width / img.width
        , crop = (resize*img.height - dimensions.height)/resize;

      ctx.drawImage(img, 0, crop/2, img.width, img.height - crop, 0, 0, dimensions.width, dimensions.height);
    };

    var out = fs.createWriteStream(destination)
      , stream = canvas.jpegStream();

    stream.on('data', function(chunk) {
      out.write(chunk);
    });

    stream.on('end', callback);

  });

};